/** Tasks — checklist (same family as Figma menu icons). */
export function IconTasks(props: SVGProps<SVGSVGElement>) {
  return (
    <svg {...ICON} fill="none" {...props}>
      <path
        d="M9.625 8.75H21.875M9.625 14H21.875M9.625 19.25H21.875"
        stroke="currentColor"
        strokeWidth="1.75"
        strokeLinecap="round"
      />
      <path
        d="M5.25 8.75L6.125 9.625L7.875 7.875M5.25 14L6.125 14.875L7.875 13.125M5.25 19.25L6.125 20.125L7.875 18.375"
        stroke="currentColor"
        strokeWidth="1.75"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

/** Tuck away — moon, optically matched to the other 28×28 glyphs. */
export function IconMoon(props: SVGProps<SVGSVGElement>) {
  return (
    <svg {...ICON} fill="none" {...props}>
      <path
        d="M21.875 15.531C20.891 19.031 17.719 21.438 14 21.438C9.238 21.438 5.25 17.45 5.25 12.688C5.25 9.031 7.569 5.906 10.938 4.813C10.5 5.469 10.281 6.256 10.281 7.088C10.281 10.938 13.394 14.05 17.244 14.05C18.119 14.05 18.944 13.881 19.688 13.575C19.319 14.306 18.725 14.956 17.969 15.444C19.775 15.306 21.438 14.569 22.663 13.344C22.531 14.1 22.269 14.844 21.875 15.531Z"
        stroke="currentColor"
        strokeWidth="1.75"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

export type MenuIconId = "chat" | "tasks" | "settings" | "tuck";

export function MenuIcon({ id, size = 28 }: { id: MenuIconId; size?: number }) {
  const style = { width: size, height: size, display: "block" as const };
  switch (id) {
    case "chat":
      return <IconChat style={style} />;
    case "tasks":
      return <IconTasks style={style} />;
    case "settings":
      return <IconSettings style={style} />;
    case "tuck":
      return <IconMoon style={style} />;
  }
}
